import { useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React from 'react';
import { Pressable, StyleSheet, Text, View } from 'react-native';
import { RootStackParamList } from '../navigation/AppNavigator';
import { createShadow } from '../styles/shadows';

type TabKey = 'OwnerHome' | 'OwnerOrders' | 'OwnerApprovals' | 'OwnerInventory' | 'OwnerCustomers';

const tabs: Array<{ key: TabKey; label: string; short: string }> = [
  { key: 'OwnerHome', label: 'Home', short: 'H' },
  { key: 'OwnerOrders', label: 'Orders', short: 'O' },
  { key: 'OwnerApprovals', label: 'Approvals', short: 'A' },
  { key: 'OwnerInventory', label: 'Stock', short: 'S' },
  { key: 'OwnerCustomers', label: 'Customers', short: 'C' }
];

const OwnerBottomNav = ({ active }: { active: TabKey }) => {
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();

  return (
    <View style={styles.container}>
      {tabs.map((tab) => {
        const selected = tab.key === active;
        return (
          <Pressable key={tab.key} style={styles.item} onPress={() => navigation.navigate(tab.key)}>
            <View style={[styles.iconWrap, selected && styles.iconWrapSelected]}>
              <Text style={[styles.iconText, selected && styles.iconTextSelected]}>{tab.short}</Text>
            </View>
            <Text style={[styles.label, selected && styles.labelSelected]}>{tab.label}</Text>
          </Pressable>
        );
      })}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'absolute',
    left: 16,
    right: 16,
    bottom: 8,
    backgroundColor: 'white',
    borderRadius: 22,
    flexDirection: 'row',
    justifyContent: 'space-between',
    paddingVertical: 10,
    paddingHorizontal: 10,
    ...createShadow({ color: '#10324A', opacity: 0.12, radius: 16, elevation: 8 })
  },
  item: {
    flex: 1,
    alignItems: 'center'
  },
  iconWrap: {
    width: 30,
    height: 30,
    borderRadius: 15,
    backgroundColor: '#EAF7FF',
    alignItems: 'center',
    justifyContent: 'center'
  },
  iconWrapSelected: {
    backgroundColor: '#0D8DD8'
  },
  iconText: {
    color: '#0D63A8',
    fontSize: 12,
    fontWeight: '800'
  },
  iconTextSelected: {
    color: 'white'
  },
  label: {
    marginTop: 6,
    color: '#6D8699',
    fontSize: 10,
    fontWeight: '700'
  },
  labelSelected: {
    color: '#0D63A8'
  }
});

export default OwnerBottomNav;
